implementation.pseudo_code:
IF user clicks 'Edit' button on a task
    CALL onEdit(task)
    // Typically opens TaskForm with task details pre-filled

FUNCTION openEdit(task: Task) {
  SET editingTask = task
  SET isFormOpen = true
}

COMPONENT TaskItem(task, onEdit) {
  RENDER task details (title, priority, category, due_date, description)
  RENDER Edit button
  ON Edit button click:
    CALL onEdit(task)
}

ASYNC FUNCTION updateTask(id: string, task: TaskCreate): Promise<Task> {
  SET response = FETCH to 'http://localhost:8000/tasks/{id}' {
    method: 'PUT',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify(task)
  }

  IF response is NOT ok THEN
    THROW Error('Failed to update task')
  END IF

  RETURN response as JSON
}

FUNCTION update_task(task_id: string, task_update: TaskCreate) -> Optional[Task] {
  CALL tasks = get_tasks()  // Load all tasks from JSON file

  FOR EACH task in tasks {
    IF task.id == task_id THEN
      CREATE updated_task = Task(id=task_id, ...task_update fields)
      SET tasks[current_index] = updated_task
      CALL save_tasks(tasks)  // Write updated tasks to JSON file
      RETURN updated_task
    END IF
  }

  RETURN null  // Task not found
}

FUNCTION validate_title(title: str) {
  IF title is empty OR title.strip() is empty THEN
    RAISE ValidationError('Title cannot be empty')
  END IF
}

FUNCTION add_task(task_create: TaskCreate) -> Task:
  // Load existing tasks from file
  tasks = get_tasks()

  // Generate unique ID for new task
  new_id = str(uuid.uuid4())

  // Create Task object with generated ID and task_create data
  new_task = Task(
    id: new_id,
    **task_create.model_dump()  // Unpack all fields from TaskCreate
  )

  // Add to tasks list
  tasks.append(new_task)

  // Persist to JSON file
  save_tasks(tasks)

  // Return created task with ID
  RETURN new_task
